import { Component, inject, Input, Output, EventEmitter } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { LlmSettingsService } from '../../services/llm-settings.service';
import { DataService } from '../../data.service';
import {
  LlmProvider,
  EXPERIENCE_TIERS,
  ExperienceTier,
} from '../../models/llm.models';
import { PromptEditorComponent } from '../prompt-editor/prompt-editor.component';

@Component({
  selector: 'app-model-config',
  standalone: true,
  imports: [FormsModule, PromptEditorComponent],
  templateUrl: './model-config.component.html',
})
export class ModelConfigComponent {
  @Input() visible: boolean = false;
  @Output() close = new EventEmitter<void>();

  public llmSettings = inject(LlmSettingsService);
  private dataService = inject(DataService);

  showAdvanced: boolean = false;

  get activeTier(): ExperienceTier {
    return this.dataService.getCurrentTier();
  }

  get currentProviderConfig() {
    return this.llmSettings.settings().configs[
      this.llmSettings.settings().selectedProvider
    ];
  }

  availableProviders = [
    { id: 'openai', label: 'OpenAI (ChatGPT)' },
    { id: 'anthropic', label: 'Anthropic (Claude)' },
    { id: 'gemini', label: 'Google Gemini' },
    { id: 'xai', label: 'xAI (Grok)' },
    { id: 'lmstudio', label: 'LM Studio (Local)' },
    { id: 'custom', label: 'Custom / Local (e.g. Ollama)' },
  ];

  updateProvider(e: Event) {
    const select = e.target as HTMLSelectElement;
    this.llmSettings.updateProvider(select.value as LlmProvider);
  }

  updateConfigField(field: 'apiKey' | 'baseUrl' | 'model', value: string) {
    this.llmSettings.updateConfig(
      this.llmSettings.settings().selectedProvider,
      { [field]: value },
    );
  }

  toggleAdvanced() {
    this.showAdvanced = !this.showAdvanced;
  }

  onClose() {
    this.showAdvanced = false;
    this.close.emit();
  }

  onBackdropClick() {
    this.onClose();
  }
}
