import { Component, Input, inject } from '@angular/core';

import { FormsModule } from '@angular/forms';
import { AiService } from '../../services/ai.service';
import { DataService } from '../../data.service';

@Component({
  selector: 'app-interview-panel',
  standalone: true,
  imports: [FormsModule],
  templateUrl: "./interview-panel.component.html",
})
export class InterviewPanelComponent {
  @Input() jobDescription!: string;
  public aiService = inject(AiService);
  public dataService = inject(DataService);

  async generateQuestions() {
    if (!this.jobDescription.trim()) {
      this.aiService.setInterviewError(
        'Please provide a job description in the Optimizer tab first.',
      );
      return;
    }

    const resumeContext = this.dataService.buildAIContext();
    const tier = this.dataService.getCurrentTier();

    // In a real app we'd map tier to tierLabel, here we just use the id for simplicity or get it from DataService
    // We already have a helper in AiBuilderComponent but let's just pass the ID as label for now.
    const tierLabel = tier.charAt(0).toUpperCase() + tier.slice(1);

    try {
      await this.aiService.generateInterviewQuestions(
        this.jobDescription,
        resumeContext,
        tierLabel,
      );
    } catch (e) {
      console.error(e);
    }
  }
}
