import {
  Component,
  inject,
  ViewChild,
  ElementRef,
  Input,
  OnChanges,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';
import { LlmSettingsService } from '../../services/llm-settings.service';
import { DataService } from '../../data.service';
import { ExperienceTier, EXPERIENCE_TIERS } from '../../models/llm.models';

@Component({
  selector: 'app-prompt-editor',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './prompt-editor.component.html',
})
export class PromptEditorComponent implements OnChanges {
  @Input() activeTier: ExperienceTier = 'mid';
  @ViewChild('highlightLayer') highlightLayer!: ElementRef<HTMLPreElement>;

  private sanitizer = inject(DomSanitizer);
  public llmSettings = inject(LlmSettingsService);
  private dataService = inject(DataService);

  promptDraft: string = '';
  promptError: string = '';

  ngOnChanges() {
    this.promptDraft = this.llmSettings.getTierPrompt(this.activeTier);
    this.promptError = '';
  }

  get currentTierLabel(): string {
    return (
      EXPERIENCE_TIERS.find((t) => t.id === this.activeTier)?.label ??
      this.activeTier
    );
  }

  validatePromptDraft() {
    const hasJd = this.promptDraft.includes('{{JOB_DESCRIPTION}}');
    const hasResume = this.promptDraft.includes('{{MASTER_RESUME}}');
    if (!hasJd && !hasResume) {
      this.promptError =
        'Missing {{JOB_DESCRIPTION}} and {{MASTER_RESUME}} template variables.';
    } else if (!hasJd) {
      this.promptError = 'Missing {{JOB_DESCRIPTION}} template variable.';
    } else if (!hasResume) {
      this.promptError = 'Missing {{MASTER_RESUME}} template variable.';
    } else {
      this.promptError = '';
    }
  }

  syncScroll(event: Event) {
    if (this.highlightLayer) {
      const textarea = event.target as HTMLTextAreaElement;
      this.highlightLayer.nativeElement.scrollTop = textarea.scrollTop;
      this.highlightLayer.nativeElement.scrollLeft = textarea.scrollLeft;
    }
  }

  highlightedPrompt(): SafeHtml {
    let text = this.promptDraft;
    if (!text) return this.sanitizer.bypassSecurityTrustHtml('');
    text = text
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;');
    text = text.replace(
      /(\{\{.*?\}\})/g,
      '<span class="text-cyan-400 font-bold">$1</span>',
    );
    text = text.replace(
      /(&lt;\/?[A-Z_]+&gt;)/g,
      '<span class="text-blue-400 font-bold">$1</span>',
    );
    text = text.replace(
      /(^\s*\d+\.)/gm,
      '<span class="text-emerald-400">$1</span>',
    );
    text = text.replace(
      /(&quot;[A-Za-z0-9_]+&quot;)(:)/g,
      '<span class="text-sky-300">$1</span>$2',
    );
    text = text.replace(
      /(: \s*)(&quot;.*?&quot;)/g,
      '$1<span class="text-green-300">$2</span>',
    );
    text = text.replace(
      /(^\s*#+\s+.*)/gm,
      '<span class="text-fuchsia-400 font-bold">$1</span>',
    );
    text = text.replace(
      /(\[.*?\])/g,
      '<span class="text-orange-300">$1</span>',
    );
    return this.sanitizer.bypassSecurityTrustHtml(text);
  }

  saveTierPrompt() {
    if (this.promptError) return;
    this.llmSettings.setTierPromptOverride(this.activeTier, this.promptDraft);
  }

  resetTierPrompt() {
    this.llmSettings.resetTierPrompt(this.activeTier);
    this.promptDraft = this.llmSettings.getDefaultTierPrompt(this.activeTier);
    this.promptError = '';
  }
}
