import { Component, inject, Input } from '@angular/core';

import { FormsModule } from '@angular/forms';
import { AiService } from '../../services/ai.service';
import { DataService } from '../../data.service';
import { LlmSettingsService } from '../../services/llm-settings.service';
import { CoverLetterTone } from '../../models/ai.models';
import { EXPERIENCE_TIERS } from '../../models/llm.models';

@Component({
  selector: 'app-cover-letter-panel',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './cover-letter-panel.component.html',
})
export class CoverLetterPanelComponent {
  /** Job description shared from the parent (same field used in suggestion tab) */
  @Input() jobDescription: string = '';

  public aiService = inject(AiService);
  public dataService = inject(DataService);
  private llmSettings = inject(LlmSettingsService);

  selectedTone: CoverLetterTone = 'conversational';
  refineInput: string = '';
  error: string = '';
  copied: boolean = false;

  tones: {
    id: CoverLetterTone;
    label: string;
    emoji: string;
    desc: string;
  }[] = [
    {
      id: 'formal',
      label: 'Formal',
      emoji: '🏛️',
      desc: 'Finance, Law, Gov.',
    },
    {
      id: 'conversational',
      label: 'Conversational',
      emoji: '💬',
      desc: 'Tech, Product, Design',
    },
    {
      id: 'startup',
      label: 'Startup',
      emoji: '🚀',
      desc: 'Early-stage, Growth',
    },
  ];

  get letter(): string {
    return this.aiService.coverLetter();
  }
  get isWriting(): boolean {
    return this.aiService.isWritingLetter();
  }
  get wordCount(): number {
    const t = this.letter.trim();
    return t ? t.split(/\s+/).length : 0;
  }

  async generate() {
    const config = this.llmSettings.getActiveConfig();
    if (
      !config.apiKey &&
      config.provider !== 'custom' &&
      config.provider !== 'lmstudio'
    ) {
      this.error =
        'API key not configured. Go to AI Settings to configure your provider.';
      return;
    }
    if (!this.jobDescription.trim()) {
      this.error =
        'Please paste a job description in the "Optimize" tab first.';
      return;
    }
    this.error = '';
    try {
      const tier = this.dataService.getCurrentTier();
      const tierMeta = EXPERIENCE_TIERS.find((t) => t.id === tier);
      const resumeContext = this.dataService.buildAIContext();
      await this.aiService.generateCoverLetter(
        this.jobDescription,
        resumeContext,
        tier,
        tierMeta?.label ?? tier,
        this.selectedTone,
      );
    } catch (err: any) {
      this.error =
        err?.message ?? 'Failed to generate cover letter. Please try again.';
    }
  }

  async refine() {
    if (!this.refineInput.trim()) return;
    this.error = '';
    const instruction = this.refineInput;
    this.refineInput = '';
    try {
      await this.aiService.refineCoverLetter(instruction);
    } catch (err: any) {
      this.error = err?.message ?? 'Failed to refine letter.';
      this.refineInput = instruction;
    }
  }

  async copyToClipboard() {
    await navigator.clipboard.writeText(this.letter);
    this.copied = true;
    setTimeout(() => (this.copied = false), 2000);
  }

  downloadAsTxt() {
    const blob = new Blob([this.letter], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'cover-letter.txt';
    a.click();
    URL.revokeObjectURL(url);
  }
}
