import { Component, inject, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { AiService } from '../services/ai.service';
import { DataService } from '../data.service';
import { AIProposal } from '../models/ai.models';
import { LlmSettingsService } from '../services/llm-settings.service';
import { ExperienceTier, EXPERIENCE_TIERS } from '../models/llm.models';
import { AtsPanelComponent } from './ats-panel/ats-panel.component';
import { CoverLetterPanelComponent } from './cover-letter-panel/cover-letter-panel.component';
import { InterviewPanelComponent } from './interview-panel/interview-panel.component';
import { ModelConfigComponent } from './model-config/model-config.component';

export type AiTab =
  | 'optimizer'
  | 'improver'
  | 'ats'
  | 'cover-letter'
  | 'interview';

@Component({
  selector: 'app-ai-builder',
  standalone: true,
  imports: [
    CommonModule,
    FormsModule,
    AtsPanelComponent,
    CoverLetterPanelComponent,
    InterviewPanelComponent,
    ModelConfigComponent,
  ],
  templateUrl: './ai-builder.component.html',
  styleUrl: './ai-builder.component.scss',
})
export class AiBuilderComponent implements OnInit {
  private router = inject(Router);
  public aiService = inject(AiService);
  public dataService = inject(DataService);
  public llmSettings = inject(LlmSettingsService);

  experienceTiers = EXPERIENCE_TIERS;

  private _activeTab: AiTab = 'optimizer';
  get activeTab(): AiTab {
    return this._activeTab;
  }
  set activeTab(value: AiTab) {
    if (
      (this._activeTab === 'optimizer' || this._activeTab === 'improver') &&
      (value === 'optimizer' || value === 'improver') &&
      this._activeTab !== value
    ) {
      this.clearHistory();
    }
    this._activeTab = value;
  }

  jobDescription: string = '';
  improverFocus: string = '';

  chatInput: string = '';
  includeCurrentResume: boolean = true;
  errorState: {
    type: 'generate' | 'resolve';
    proposal?: AIProposal;
    msg: string;
  } | null = null;

  /** True when there are results to show - derived from the signals so it survives page refresh */
  get hasGenerated(): boolean {
    return this.aiService.chatHistory().length > 0;
  }

  showSettings: boolean = false;

  openSettings() {
    this.showSettings = true;
  }

  closeSettings() {
    this.showSettings = false;
  }

  // Minimal list used only for error message lookup in generate()
  private readonly providerLabels: Record<string, string> = {
    openai: 'OpenAI (ChatGPT)',
    anthropic: 'Anthropic (Claude)',
    gemini: 'Google Gemini',
    xai: 'xAI (Grok)',
    lmstudio: 'LM Studio (Local)',
    custom: 'Custom / Local',
  };

  ngOnInit() {
    if (typeof localStorage !== 'undefined') {
      const savedJD = localStorage.getItem('ai_builder_jd');
      if (savedJD) this.jobDescription = savedJD;
      const savedImp = localStorage.getItem('ai_builder_improver');
      if (savedImp) this.improverFocus = savedImp;
      const savedInc = localStorage.getItem('ai_builder_include_resume');
      if (savedInc !== null) this.includeCurrentResume = savedInc === 'true';
    }
  }

  saveFormState() {
    if (typeof localStorage === 'undefined') return;
    localStorage.setItem('ai_builder_jd', this.jobDescription);
    localStorage.setItem('ai_builder_improver', this.improverFocus);

    localStorage.setItem(
      'ai_builder_include_resume',
      String(this.includeCurrentResume),
    );
  }

  goBack() {
    this.router.navigate(['/']);
  }

  async generate() {
    // If history is empty, rely on jobDescription/improverFocus depending on tab
    // If hitting chat follow-up, rely on chatInput
    const isFirstCall = this.aiService.chatHistory().length === 0;

    let submittedText = '';
    if (isFirstCall) {
      submittedText =
        this.activeTab === 'improver'
          ? this.improverFocus
          : this.jobDescription;
    } else {
      submittedText = this.chatInput;
    }

    if (this.activeTab === 'optimizer' && isFirstCall && !submittedText.trim())
      return;
    // Improver can have an empty initial input

    this.saveFormState();
    this.errorState = null;

    const config = this.llmSettings.getActiveConfig();
    if (
      !config.apiKey &&
      config.provider !== 'custom' &&
      config.provider !== 'lmstudio'
    ) {
      this.errorState = {
        type: 'generate',
        msg:
          'API Key is missing for ' +
          (this.providerLabels[config.provider] ?? config.provider) +
          '. Please configure it first.',
      };
      this.openSettings();
      return;
    }

    // Clear the chat input since that's what was submitted (if it's a follow-up)
    if (!isFirstCall) {
      this.chatInput = '';
    }

    try {
      const contextString = this.includeCurrentResume
        ? this.dataService.buildAIContext()
        : null;

      const mode = this.activeTab === 'improver' ? 'general' : 'job';
      await this.aiService.generateSuggestions(
        submittedText,
        contextString,
        mode,
      );
    } catch (err: any) {
      if (!isFirstCall) this.chatInput = submittedText; // Restore on failure
      this.errorState = {
        type: 'generate',
        msg:
          err?.message ??
          'An unexpected error occurred. Check your API key and try again.',
      };
    }
  }

  getSectionTypeName(typeEnum: any): string {
    const names = [
      'Personal Info',
      'Skills',
      'Experience',
      'Projects',
      'Education',
      'Achievement',
    ];
    return names[typeEnum] || 'Section';
  }

  getItemDetails(itemId: string) {
    return this.dataService.getItemDetails(itemId);
  }

  acceptProposal(proposal: AIProposal) {
    if (proposal.action.type === 'toggle') {
      this.dataService.setItemActive(
        proposal.action.itemId,
        proposal.action.targetState,
      );
      this.aiService.updateProposalStatus(proposal.id, 'accepted');
    } else if (proposal.action.type === 'modify') {
      this.dataService.modifyBullet(
        proposal.action.itemId,
        proposal.action.newText,
      );
      this.aiService.updateProposalStatus(proposal.id, 'accepted');
    } else if (proposal.action.type === 'add_section') {
      this.dataService.addOrUpdateSection({
        type: proposal.action.sectionType,
        content: proposal.action.content,
      } as any);
      this.aiService.updateProposalStatus(proposal.id, 'accepted');
    }

    // Auto-rescore ATS if the preference is enabled and a JD is available
    const prefs = this.llmSettings.getPreferences();
    if (prefs.autoRescore && this.jobDescription.trim()) {
      const tier = this.dataService.getCurrentTier();
      const tierMeta = EXPERIENCE_TIERS.find((t) => t.id === tier);
      this.aiService
        .analyzeAtsMatch(
          this.jobDescription,
          this.dataService.buildAIContext(),
          tier,
          tierMeta?.label ?? tier,
          tierMeta?.sublabel ?? '',
        )
        .catch(() => {
          /* silent background failure */
        });
    }
  }

  rejectProposal(proposal: AIProposal) {
    this.aiService.updateProposalStatus(proposal.id, 'rejected');
  }

  async resolveQuestion(proposal: AIProposal) {
    if (!proposal.userReply?.trim()) return;
    try {
      this.errorState = null;
      await this.aiService.resolveQuestion(proposal, proposal.userReply);
    } catch (err: any) {
      this.errorState = {
        type: 'resolve',
        proposal,
        msg: err?.message ?? 'Failed to resolve the question with AI.',
      };
    }
  }

  retryErrorAction() {
    if (!this.errorState) return;
    if (this.errorState.type === 'generate') {
      this.generate();
    } else if (this.errorState.type === 'resolve' && this.errorState.proposal) {
      this.resolveQuestion(this.errorState.proposal);
    }
  }

  clearHistory() {
    this.aiService.clearState();
    this.errorState = null;
    this.chatInput = '';
  }
}
